// src/critic/evidence-guard.ts
function guardCritique(out2, mode, citationCorpus, changedFiles) {
  if (mode === "PASSIVE_BUBBLE")
    return { accept: true };
  if (mode === "HARD_SUPPRESS")
    return { accept: true };
  if (out2.evidence.length === 0) {
    return { accept: false, reason: "NORMAL mode but evidence array empty" };
  }
  for (const item of out2.evidence) {
    if (!citationCorpus.includes(item.snippet)) {
      const preview = item.snippet.length > 60 ? `${item.snippet.slice(0, 60)}...` : item.snippet;
      return {
        accept: false,
        reason: `snippet not in evidence_corpus: ${preview}`
      };
    }
    if (!changedFiles.has(item.file) && !citationCorpus.includes(item.file)) {
      return {
        accept: false,
        reason: `evidence file not in changed-files or corpus: ${item.file}`
      };
    }
  }
  return { accept: true };
}

