    const parseSpanPB = tracer.startSpan({ name: "siltpoke.response.parse", kind: "INTERNAL", parent: rootSpan });
    tracer.setKind(parseSpanPB, "parser");
    tracer.setInput(parseSpanPB, { raw_text: "(parsed inside callBrain)" });
