// src/critic/intent/regex-rules.ts
var INTENT_RULES = [
  { id: "bugfix-keyword-fix", classification: "bugfix", pattern: /\b(fix|fixes|fixed|fixing)\b/i, confidence: 0.85, applies_to: "both" },
  { id: "bugfix-keyword-bug", classification: "bugfix", pattern: /\b(bug|crash|broken|error|issue|bugfix)\b/i, confidence: 0.7, applies_to: "both" },
  { id: "bugfix-conv-commit", classification: "bugfix", pattern: /^fix(\(.+\))?:/i, confidence: 0.95, applies_to: "commit_msg" },
  { id: "feature-keyword-add", classification: "feature", pattern: /\b(add|adds|added|adding|implement|implements)\b/i, confidence: 0.75, applies_to: "both" },
  { id: "feature-keyword-new", classification: "feature", pattern: /\b(new feature|introduce|introduces)\b/i, confidence: 0.8, applies_to: "both" },
  { id: "feature-conv-commit", classification: "feature", pattern: /^feat(\(.+\))?:/i, confidence: 0.95, applies_to: "commit_msg" },
  { id: "refactor-keyword", classification: "refactor", pattern: /\b(refactor(?:ing|ed|s)?|rename|extract|cleanup|reorganize|restructure|simplify)\b/i, confidence: 0.85, applies_to: "both" },
  { id: "refactor-conv-commit", classification: "refactor", pattern: /^refactor(\(.+\))?:/i, confidence: 0.95, applies_to: "commit_msg" },
  { id: "chore-conv-commit", classification: "chore", pattern: /^(chore|docs|test|ci|build|perf)(\(.+\))?:/i, confidence: 0.95, applies_to: "commit_msg" },
  { id: "chore-keyword", classification: "chore", pattern: /\b(update deps|bump|dependencies|formatting|lint)\b/i, confidence: 0.75, applies_to: "both" },
  { id: "exploration-keyword", classification: "exploration", pattern: /\b(try|trying|experiment|explore|prototype|spike|wip)\b/i, confidence: 0.7, applies_to: "both" }
];

// src/critic/intent/classifier.ts
function classifyIntent(input) {
  const signals = [];
  const scores = new Map;
  for (const rule of INTENT_RULES) {
    const inUser = (rule.applies_to === "user_message" || rule.applies_to === "both") && rule.pattern.test(input.user_message);
    const inCommit = (rule.applies_to === "commit_msg" || rule.applies_to === "both") && input.commit_msg !== null && rule.pattern.test(input.commit_msg);
    if (inUser) {
      signals.push({ source: "user_message", matched_rule_id: rule.id, confidence: rule.confidence });
      scores.set(rule.classification, (scores.get(rule.classification) ?? 0) + rule.confidence);
    }
    if (inCommit) {
      signals.push({ source: "commit_msg", matched_rule_id: rule.id, confidence: rule.confidence });
      scores.set(rule.classification, (scores.get(rule.classification) ?? 0) + rule.confidence);
    }
  }
  const onlyTestDocs = input.changed_file_exts.size > 0 && [...input.changed_file_exts].every((ext) => ["md", "test.ts", "test.tsx", "spec.ts"].includes(ext));
  if (onlyTestDocs) {
    signals.push({ source: "file_extensions", matched_rule_id: "ext-only-test-docs", confidence: 0.6 });
    scores.set("chore", (scores.get("chore") ?? 0) + 0.6);
  }
  if (scores.size === 0) {
    return { classification: "exploration", confidence: 0.3, signals: [], signal_source: "regex" };
  }
  let winner = "exploration";
  let winnerScore = 0;
  for (const [k, v] of scores) {
    if (v > winnerScore) {
      winner = k;
      winnerScore = v;
    }
  }
  const confidence = Math.min(0.99, winnerScore / 1.5);
  return { classification: winner, confidence, signals, signal_source: "regex" };
}

// src/critic/intent/capture.ts
var MAX_REPLY_CHARS = 1200;
function stripUserTurnNoise(text) {
  const lines = text.split(`
`);
  const kept = [];
  let inSystemTag = false;
  for (const raw of lines) {
    const line = raw.trim();
    if (line.length === 0) {
      kept.push("");
      continue;
    }
    if (/^\[Image:\s*source:.*\]$/i.test(line))
      continue;
    if (/^<(user-prompt-submit-hook|system-reminder)/i.test(line)) {
      inSystemTag = !/<\/(user-prompt-submit-hook|system-reminder)>\s*$/i.test(line);
      continue;
    }
    if (inSystemTag) {
      if (/<\/(user-prompt-submit-hook|system-reminder)>\s*$/i.test(line)) {
        inSystemTag = false;
      }
      continue;
    }
    kept.push(raw);
  }
  return kept.join(`
`).trim();
}
function extractFirstReplyParagraph(text) {
  const lines = text.split(`
`);
  let start2 = 0;
  while (start2 < lines.length && /^\s*\[tool\s+[A-Za-z]+\]/i.test(lines[start2] ?? "")) {
    start2++;
  }
  const after = lines.slice(start2).join(`
`).trim();
  if (after.length === 0)
    return "";
  const paras = after.split(/\n\n+/).map((p) => p.trim()).filter((p) => p.length > 0);
  if (paras.length === 0)
    return "";
  return paras[0];
}
function captureIntent(turns, _commitMsg) {
  let user_raw_query = null;
  let lastUserIdx = -1;
  for (let i2 = turns.length - 1;i2 >= 0; i2--) {
    const t = turns[i2];
    if (t.role !== "user")
      continue;
    const cleaned = stripUserTurnNoise(t.text);
    if (cleaned.length === 0)
      continue;
    user_raw_query = cleaned;
    lastUserIdx = i2;
    break;
  }
  let agent_reply = null;
  if (lastUserIdx >= 0) {
    for (let i2 = lastUserIdx + 1;i2 < turns.length; i2++) {
      const t = turns[i2];
      if (t.role !== "assistant")
        continue;
      const para = extractFirstReplyParagraph(t.text);
      if (para.length === 0)
        continue;
      agent_reply = para.slice(0, MAX_REPLY_CHARS);
      break;
    }
  }
  return { user_raw_query, agent_reply };
}

