      console.error(`[siltpoke memory] consolidated: +${consolidateResult.apply.added} active, ${consolidateResult.apply.skipped} bumped, discarded: ${consolidateResult.apply.discarded}, ${consolidateResult.prune.factsPruned + consolidateResult.prune.pendingPruned} pruned`);
